using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;

// ── Configuration ──────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ── DI container ───────────────────────────────────────────────────────
var services = new ServiceCollection();

services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, apiKey));

var sp = services.BuildServiceProvider();

var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// ── Tools ──────────────────────────────────────────────────────────────
var tools = new ResearchTools(sp.GetRequiredService<ILoggerFactory>());
var aiTools = new List<AITool>
{
    AIFunctionFactory.Create(tools.SearchWeb),
    AIFunctionFactory.Create(tools.SaveNote),
    AIFunctionFactory.Create(tools.GetNotes),
};

// ── Agent ──────────────────────────────────────────────────────────────
const string instructions = """
    You are a research assistant. Your job is to research a topic thoroughly and produce a clear summary.

    Workflow:
    1. Break the topic into 2-3 search queries that cover different angles.
    2. Use the SearchWeb tool for each query to gather information.
    3. Use the SaveNote tool to record key findings as you go.
    4. After gathering enough information, use GetNotes to review everything you've collected.
    5. Produce a well-structured summary with sections and source references.

    Be concise but thorough. Cite your sources.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking tools.",
    tools: aiTools,
    loggerFactory: loggerFactory);

// ── Run ────────────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       Research Agent (MAF + MEAI)    ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "recent advances in quantum computing";
}

Console.WriteLine($"\nResearching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions { Temperature = 0f, MaxOutputTokens = 2048 });

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions);

Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("              RESEARCH SUMMARY         ");
Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();

if (tools.NoteCount > 0)
{
    Console.WriteLine($"[{tools.NoteCount} notes were collected during research]");
}

// ── Tool implementations ───────────────────────────────────────────────

/// <summary>Tools available to the research agent for web search and note-taking.</summary>
sealed class ResearchTools
{
    private readonly List<(string Title, string Content, string Source)> _notes = [];
    private readonly HttpClient _httpClient = new();
    private readonly ILogger _logger;

    public int NoteCount => _notes.Count;

    public ResearchTools(ILoggerFactory loggerFactory)
    {
        _logger = loggerFactory.CreateLogger<ResearchTools>();
    }

    [Description("Search the web for information on a query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up on the web")] string query)
    {
        _logger.LogDebug("Searching web for: {QueryLength} chars", query.Length);

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var json = await _httpClient.GetFromJsonAsync<JsonElement>(url);

            var results = new List<string>();

            // Abstract (main result)
            var abstractText = json.GetProperty("Abstract").GetString();
            var abstractSource = json.GetProperty("AbstractSource").GetString();
            var abstractUrl = json.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"**{abstractSource}**: {abstractText}\nSource: {abstractUrl}");
            }

            // Related topics
            if (json.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var topicUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add($"- {text}\n  URL: {topicUrl}");
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for '{query}'. Try rephrasing the search query with different keywords.";
            }

            return $"Search results for '{query}':\n\n{string.Join("\n\n", results)}";
        }
        catch (Exception ex)
        {
            _logger.LogWarning(ex, "Web search failed");
            return $"Search failed for '{query}': {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note with a title, content, and source URL for later reference.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The content or key finding to save")] string content,
        [Description("The source URL or reference")] string source)
    {
        _notes.Add((title, content, source));
        _logger.LogDebug("Note saved: {TitleLength} chars", title.Length);
        return $"Note #{_notes.Count} saved: '{title}'";
    }

    [Description("Retrieve all saved research notes to review findings before writing the summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var formatted = _notes.Select((n, i) =>
            $"Note #{i + 1}: {n.Title}\n{n.Content}\nSource: {n.Source}");

        return $"All research notes ({_notes.Count} total):\n\n{string.Join("\n\n---\n\n", formatted)}";
    }
}

